#include <stdio.h>
#include <stdlib.h>

// Define the structure for a linked list node
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Function to create a new node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to delete the middle node of a linked list
Node* deleteMiddle(Node* head) {
    if (head == NULL || head->next == NULL) {
        // Only one node → becomes empty
        free(head);
        return NULL;
    }

    Node* slow = head;
    Node* fast = head;
    Node* prev = NULL;

    // Move slow and fast pointers to find middle
    while (fast != NULL && fast->next != NULL) {
        fast = fast->next->next;
        prev = slow;
        slow = slow->next;
    }

    // Delete middle node
    prev->next = slow->next;
    free(slow);

    return head;
}

// Function to print the linked list
void printList(Node* head) {
    while (head) {
        printf("%d ", head->data);
        head = head->next;
    }
    printf("\n");
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node* head = NULL;
        Node* temp = NULL;
        for (int i = 0; i < N; i++) {
            int data;
            scanf("%d", &data);
            Node* newNode = createNode(data);
            if (head == NULL) {
                head = newNode;
                temp = head;
            } else {
                temp->next = newNode;
                temp = temp->next;
            }
        }
        head = deleteMiddle(head);
        if (head == NULL) {
            printf("-1\n");
        } else {
            printList(head);
        }
    }
    return 0;
}

